/**
 * Chats API
 */
export class ChatsAPI {
    constructor(http) {
        this.http = http;
    }
    /**
     * List chats with cursor-based pagination
     */
    async list(params) {
        return this.http.request('post', '/chats/list', { data: params });
    }
    /**
     * Get a chat by ID
     */
    async get(chatId) {
        return this.http.request('get', `/chats/${chatId}`);
    }
    /**
     * Update a chat
     */
    async update(chatId, data) {
        return this.http.request('post', `/chats/${chatId}`, { data });
    }
    /**
     * Delete a chat
     */
    async delete(chatId) {
        return this.http.request('delete', `/chats/${chatId}`);
    }
    /**
     * Get chat trace (for debugging/observability)
     */
    async getTrace(chatId) {
        return this.http.request('get', `/chats/${chatId}/trace`);
    }
}
export function createChatsAPI(http) {
    return new ChatsAPI(http);
}
